# Verify the three main solutions
def check(f):
    for m in range(-5,6):
        for n in range(-5,6):
            if f(m*m+n*n) != f(m)**2 + f(n)**2:
                return False
    return True

f0 = lambda x: 0
f1 = lambda x: x
f2 = lambda x: abs(x)
print('f=0:', check(f0))
print('f=x:', check(f1))
print('f=|x|:', check(f2))
